async function main() {
  let successCount = 0;
  let failCount = 0;

  for (const update of updates) {
    const wordCount = update.description.split(/\s+/).length;
    const metaLen = update.metaDescription.length;
    console.log(`Processing: ${update.slug}`);
    console.log(`  Description word count: ${wordCount}`);
    console.log(`  Meta description length: ${metaLen}`);

    if (wordCount < 250) {
      console.log(`  ⚠️ WARNING: Description word count is ${wordCount}, expected 250+`);
    }
    if (metaLen < 130 || metaLen > 155) {
      console.log(`  ⚠️ WARNING: Meta description length is ${metaLen}, expected 130-155`);
    }

    try {
      const result = await prisma.product.update({
        where: { slug: update.slug },
        data: {
          description: update.description,
          metaDescription: update.metaDescription,
        },
      });
      console.log(`  ✅ Updated successfully`);
      successCount++;
    } catch (err) {
      console.log(`  ❌ Failed: ${err.message}`);
      failCount++;
    }
  }

  console.log(`\n=== SUMMARY ===`);
  console.log(`Total: ${updates.length}`);
  console.log(`Success: ${successCount}`);
  console.log(`Failed: ${failCount}`);
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
